external_knowledge:
- 'more substantial loans' refers to loans with amounts greater than $100,000;
- 'up-to-date with their payments' is equivalent to loans with a status of 'current';
- 'active pools' refers to loan pools with a status of 'active';
- 'most expensive interest' refers to sorting the interest rates in descending order.

sql:
SELECT servicing_spread
FROM servicing_costs
WHERE cost_date = '2023-01-20';

SELECT pool_identifier 
FROM loan_pools 
WHERE status = 'active' AND creation_date > '2022-01-01';

SELECT pool_identifier
FROM loan_pools
WHERE total_loan_amount = (
    SELECT MAX(total_loan_amount)
    FROM loan_pools
);

SELECT loan_id, weighted_average_spread, risk_rating
FROM loan_analysis
WHERE loan_id = 1;

SELECT * 
FROM loan_pools 
WHERE pool_id = 1;

SELECT COUNT(*) AS total_active_loan_pools
FROM loan_pools
WHERE status = 'active';

SELECT ROUND(AVG(interest_rate), 2) AS "Average Interest Rate for Fixed-Rate Loans"
FROM loans
WHERE loan_type = 'fixed-rate';

SELECT loan_pools.pool_identifier, loans.borrower_name
FROM loan_pools
INNER JOIN loans ON loan_pools.pool_id = loans.pool_id;
